import '../lib/model.dart';
import '../lib/outbox.dart';
import '../lib/replica.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

void main() {
  final queue = Outbox();
  queue.enqueue(Mutation(
    id: 'rename',
    key: 'name',
    value: 'Field kit',
    basedOnRevision: 12,
  ));
  queue.openSession(40);
  queue.enqueue(Mutation(
    id: 'tag',
    key: 'tag',
    value: 'urgent',
    basedOnRevision: 12,
  ));
  final replacementSession = queue.openSession(41);
  check(
    replacementSession.map((item) => item.id).join('|') == 'rename|tag',
    'a replacement transport receives old and newly queued intent in order',
  );

  final replica = Replica(
    revision: 12,
    values: {'draft': 'seed', 'remoteFlag': 'off'},
  );
  replica.edit('draft-edit', 'draft', 'offline text');
  replica.receiveSnapshot(Snapshot(15, {'remoteFlag': 'on'}));
  check(
    replica.visible['draft'] == 'offline text',
    'pending creation survives a snapshot that does not contain its key',
  );
  check(replica.visible['remoteFlag'] == 'on', 'the new server field is retained');
  check(
    replica.outbox.pending.single.basedOnRevision == 15,
    'the surviving creation is ready for the new server revision',
  );
}
